import clsx from 'clsx';
import { noop } from 'lodash-es';
import { forwardRef, useRef, type MouseEventHandler } from 'react';
import { useIntl } from 'react-intl';

import { ChevronRightSmallIcon } from '@dynatrace/strato-icons';

import { useSeriesItemDisplayState } from './hooks/use-series-item-display-state.js';
import { SeriesActionsHeader } from './SeriesActionsHeader.js';
import { SeriesItemContent } from './SeriesItemContent.js';
import { useId } from '../../../../../../core/hooks/useId.js';
import { COPY_TO_CLIPBOARD_MESSAGES } from '../../../copy-to-clipboard/copy-to-clipboard-messages.js';
import { ChartActionsMenuAsync } from '../../../series-action/ChartActionsMenuAsync.js';
import { TOOLTIP_CONTENT_PADDING } from '../../constants.js';
import { useExternalConfig } from '../../contexts/ExternalConfigContext.js';
import { useDefaultLabels } from '../../hooks/useDefaultLabels.js';
import { useSelector, useTooltipSnapshot } from '../../selectors.js';
import {
  chevron,
  chevronRightAligned,
  seriesItemActive,
  seriesItemWithChevron,
  seriesItemWrapper,
  TOOLTIP_MAX_WIDTH,
} from '../../tooltip.sty.js';
import type { SeriesItemProps } from '../../types/series.js';
import { InternalSeriesItemProps } from '../../types/series.js';
import { useTooltipReducer } from '../../useTooltipReducer.js';
import { getDefaultAction } from '../../utils/get-copy-action.js';

const ACTIVE_SERIES_HOVER_DELAY = 300;
const CHEVRON_SLOT_WIDTH = 20;

export const SeriesItem = (props: SeriesItemProps) => {
  const intl = useIntl();
  const { pinned } = useTooltipSnapshot();
  const labelFor = useDefaultLabels();
  const { actions, ...restProps } = props as InternalSeriesItemProps;
  const { symbolPosition = 'left', defaultActionsConfig } = useExternalConfig();
  const hasActions = actions !== undefined || defaultActionsConfig.size > 0;
  const dispatch = useTooltipReducer();
  const rowId = useId();
  const isOpen = useSelector(({ activeSeries }) => activeSeries === rowId);
  const { activeSeries } = useTooltipSnapshot();
  const menuDelayRef = useRef(0);
  const asyncActions = actions ? async () => actions() : undefined;

  const triggerLeftTooltip: MouseEventHandler<HTMLDivElement> = (event) => {
    event.stopPropagation();
    dispatch({ type: 'TOOLTIP_MOUSE_LEAVE' })();
  };
  const handleClick: MouseEventHandler<HTMLButtonElement> = (event) => {
    event.stopPropagation();
    menuDelayRef.current = 0;
    dispatch({
      type: 'SET_ACTIVE_SERIES',
      payload: { activeSeries: rowId },
    })();
  };
  const handlePointerMove = () => {
    menuDelayRef.current = ACTIVE_SERIES_HOVER_DELAY;
    dispatch({
      type: 'SET_ACTIVE_SERIES',
      payload: { activeSeries: rowId },
    })();
  };
  const defaultActions = !pinned
    ? null
    : [...defaultActionsConfig.entries()].map(([accessor, config]) => {
        const message = intl.formatMessage(
          config.messageLabel ?? COPY_TO_CLIPBOARD_MESSAGES.copyField,
          {
            field: labelFor?.(
              config.field,
              config.customLabel,
            )?.toLocaleLowerCase(),
          },
        );
        return getDefaultAction(props, accessor, message);
      });

  return (
    <button
      className={clsx(
        activeSeries === rowId && seriesItemActive,
        seriesItemWrapper,
      )}
      onClick={handleClick}
      onPointerMove={handlePointerMove}
      onKeyDown={noop}
      data-testid="menu-trigger"
    >
      <ChartActionsMenuAsync
        hasActions={hasActions}
        defaultActions={defaultActions}
        actions={asyncActions}
        isOpen={isOpen}
        header={<SeriesActionsHeader text={props.name} />}
        onActionSelected={triggerLeftTooltip}
        delay={menuDelayRef.current}
      >
        <WithSymbol
          symbolPosition={symbolPosition}
          hasActions={hasActions}
          {...restProps}
        />
      </ChartActionsMenuAsync>
    </button>
  );
};

type SeriesWithSymbolProps = Omit<InternalSeriesItemProps, 'actions'> & {
  symbolPosition: 'left' | 'right';
  hasActions: boolean;
};

const WithSymbol = forwardRef<HTMLDivElement, SeriesWithSymbolProps>(
  (props, ref) => {
    const containerWidth = TOOLTIP_MAX_WIDTH - TOOLTIP_CONTENT_PADDING;
    const {
      color,
      multiLine = false,
      name,
      description,
      shape,
      iconStyle,
      icon,
      symbol,
    } = props;
    const { symbolPosition, hasActions } = props;
    const seriesContentMaxWidth = hasActions
      ? containerWidth - CHEVRON_SLOT_WIDTH
      : containerWidth;
    const {
      nameText,
      descriptionText,
      fullDescriptionText,
      isDescriptionTruncated,
      descriptionShouldUseMultiLineCss,
      descriptionMultiLineMode,
      displayValueText,
      displayRelativeValueText,
      fullValueText,
      fullRelativeValueText,
      nameTextStyle,
      nameStyle,
    } = useSeriesItemDisplayState({
      ...props,
      maxWidth: seriesContentMaxWidth,
    });
    return (
      <div ref={ref} className={seriesItemWithChevron}>
        <SeriesItemContent
          color={color}
          name={name}
          description={description}
          nameText={nameText}
          descriptionText={descriptionText}
          fullDescriptionText={fullDescriptionText}
          isDescriptionTruncated={isDescriptionTruncated}
          descriptionShouldUseMultiLineCss={descriptionShouldUseMultiLineCss}
          descriptionMultiLineMode={descriptionMultiLineMode}
          displayValueText={displayValueText}
          displayRelativeValueText={displayRelativeValueText}
          fullValueText={fullValueText}
          fullRelativeValueText={fullRelativeValueText}
          nameTextStyle={nameTextStyle}
          nameStyle={nameStyle}
          multiLine={multiLine}
          symbolPosition={symbolPosition}
          shape={shape}
          symbol={symbol}
          iconStyle={iconStyle}
          icon={icon}
          hasChevron={hasActions}
          maxWidth={seriesContentMaxWidth}
        />
        {hasActions && (
          <span
            className={clsx(
              chevron,
              symbolPosition === 'right' && chevronRightAligned,
            )}
            aria-hidden
          >
            <ChevronRightSmallIcon size={16} />
          </span>
        )}
      </div>
    );
  },
);
